VALUES
  ('generalpolice-0395e56f-moex-00072', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '有關立法委員之文件調閱權，下列敘述何者錯誤？', '["立法院得向檢察機關調閱已偵查終結而不起訴處分確定之案件卷證", "文件調閱權之行使，係經院會或委員會之決議行之", "國家機關獨立行使職權受憲法保障者，文件調閱權之行使即應受限制", "考試機關對於應考成績之評定，無涉機關獨立行使職權，得經院會決議調閱文件原本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00073', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '關於考試院，下列敘述何者錯誤？', '["考試院為合議制機關", "考試院院長並為考試委員及考試院會議主席", "考試委員由總統提名，經立法院同意後任命", "考試院就所掌事項得向立法院提出法律案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00074', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '依憲法訴訟法規定，下列何種憲法法庭判決，必須經過言詞辯論才能作成？', '["總統彈劾案", "統一解釋法律案件", "機關爭議案件", "地方自治保障案件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00075', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '下列何種情形，限制人身自由之行政機關毋須於24小時內移送法院審理？', '["衛生主管機關認疑似被傳染者有強制隔離之必要時", "人民因犯罪嫌疑被逮捕拘禁，檢察官經訊問後認有羈押之必要時", "受收容之外國人於暫時收容期間內，對於暫時收容處分表示不服時", "行政執行官拘提義務人並經詢問後，認有對義務人為管收處分之必要時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00076', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '有關訴訟權，下列敘述何者錯誤？', '["基於「有權利必有救濟」原則，人民權利受有侵害，均得向法院尋求救濟", "立法機關對於受理爭議的裁判機關及審級，有一定之裁量權，但仍應受司法審查", "特別類型案件如設置有特別程序，違反訴訟平等原則", "法院不得以法律有漏洞而拒絕審判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00077', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '憲法第19條規定，人民有依法律納稅之義務。依司法院大法官解釋，下列敘述何者錯誤？', '["國家課人民以繳納稅捐之義務時，應以法律明定租稅主體等租稅構成要件", "累進稅率使所得較高者必須負擔高額賦稅，故違反平等原則之要求", "國家提供人民稅捐減免優惠時，亦有租稅法定主義之適用", "稅捐稽徵機關絕對不得逾越法律解釋之範圍，而增加法律所無之租稅義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00078', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '依相關大法官解釋，有關中央與地方權限關係，下列敘述何者錯誤？', '["於不侵害地方自主權核心領域之限度內，中央得依據法律，使地方共負協力義務分擔全民健康保險 保險費之補助", "於符合憲法規定、法律保留原則及比例原則之下，地方自治團體得就自治事項，以自治條例規範居 民之權利義務", "地方立法機關得依中央主管機關擬訂之準則，制定地方自治團體及其所屬機關之組織自治條例以 行使自主組織權", "地方行政機關公務員未應立法院各委員會之邀請到會備詢時，立法院為有效監督，得刪減中央對地 方補助款預算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00079', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '依著作權法規定，下列何者不得為著作權之標的？', '["書法", "司法院新聞稿", "電腦程式", "建築物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00080', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '祭祀公業條例第4條第1項前段規定：「本條例施行前已存在之祭祀公業，其派下員依規約定之。」 關於該條之合憲性，下列敘述何者最符合大法官解釋之意旨？', '["該規定為性別中立，不違憲", "該規定構成實質上的性別差別待遇，違憲", "該規定構成實質上的性別差別待遇，但其目的在於維護法秩序之安定及不溯及既往原則，不違憲", "該規定為性別中立，但違反國家積極促進性別平等之義務，違憲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL),
  ('generalpolice-0395e56f-moex-00081', 'generalpolice-0395e56f', 'generalpolice-0395e56f-moex-113-3d2b73b6', 'sub-generalpolice-0395e56f-02', NULL, 'single_choice', '關於法規的失效，下列敘述何者正確？', '["法定施行期間經過後，仍須待主管機關公告，始失其效力", "法律不得授權以命令訂定失效日期", "法律之廢止，應經立法院通過，總統公布", "憲法法庭對於違憲之法規，只能宣告定期失效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:50+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "305", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察資訊管理人員"}'::jsonb, NULL)
